#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define BLOCK_SIZE 16

void random_matrix(float *I, int rows, int cols);
void runTest(int argc, char **argv);
void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <lamda> <no. of iter>\n", argv[0]);
    fprintf(stderr, "\t<rows>   - number of rows\n");
    fprintf(stderr, "\t<cols>    - number of cols\n");
    fprintf(stderr, "\t<y1> 	 - y1 value of the speckle\n");
    fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
    fprintf(stderr, "\t<x1>       - x1 value of the speckle\n");
    fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
    fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
    fprintf(stderr, "\t<no. of iter>   - number of iterations\n");

    exit(1);
}

int main(int argc, char **argv)
{
    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);
    runTest(argc, argv);

    return EXIT_SUCCESS;
}

void srad_omp_1(float *E_C, float *W_C, float *N_C, float *S_C, float *J, float *C, int cols, int rows, float q0sqr)
{
    int block_x = cols / BLOCK_SIZE;
    int block_y = rows / BLOCK_SIZE;

#pragma omp parallel for collapse(2) schedule(static)
    for (int by = 0; by < block_y; by++) {
        for (int bx = 0; bx < block_x; bx++) {
            float temp[BLOCK_SIZE][BLOCK_SIZE];
            float temp_result[BLOCK_SIZE][BLOCK_SIZE];
            float north[BLOCK_SIZE][BLOCK_SIZE];
            float south[BLOCK_SIZE][BLOCK_SIZE];
            float east[BLOCK_SIZE][BLOCK_SIZE];
            float west[BLOCK_SIZE][BLOCK_SIZE];

            // Load data into local arrays
            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;
                    int index_n = index - cols;
                    int index_s = index + cols;
                    int index_w = index - 1;
                    int index_e = index + 1;

                    // north
                    if (by == 0) {
                        north[ty][tx] = J[BLOCK_SIZE * bx + tx];
                    } else {
                        north[ty][tx] = J[index_n];
                    }
                    // south
                    if (by == block_y - 1) {
                        south[ty][tx] = J[cols * BLOCK_SIZE * (block_y - 1) + BLOCK_SIZE * bx + cols * (BLOCK_SIZE - 1) + tx];
                    } else {
                        south[ty][tx] = J[index_s];
                    }
                    // west
                    if (bx == 0) {
                        west[ty][tx] = J[cols * BLOCK_SIZE * by + cols * ty];
                    } else {
                        west[ty][tx] = J[index_w];
                    }
                    // east
                    if (bx == block_x - 1) {
                        east[ty][tx] = J[cols * BLOCK_SIZE * by + BLOCK_SIZE * (block_x - 1) + cols * ty + BLOCK_SIZE - 1];
                    } else {
                        east[ty][tx] = J[index_e];
                    }
                    temp[ty][tx] = J[index];
                }
            }

            // Compute c values
            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;
                    float jc = temp[ty][tx];
                    float n, s, w, e;

                    if (ty == 0 && tx == 0) {
                        n = north[ty][tx] - jc;
                        s = temp[ty + 1][tx] - jc;
                        w = west[ty][tx] - jc;
                        e = temp[ty][tx + 1] - jc;
                    } else if (ty == 0 && tx == BLOCK_SIZE - 1) {
                        n = north[ty][tx] - jc;
                        s = temp[ty + 1][tx] - jc;
                        w = temp[ty][tx - 1] - jc;
                        e = east[ty][tx] - jc;
                    } else if (ty == BLOCK_SIZE - 1 && tx == BLOCK_SIZE - 1) {
                        n = temp[ty - 1][tx] - jc;
                        s = south[ty][tx] - jc;
                        w = temp[ty][tx - 1] - jc;
                        e = east[ty][tx] - jc;
                    } else if (ty == BLOCK_SIZE - 1 && tx == 0) {
                        n = temp[ty - 1][tx] - jc;
                        s = south[ty][tx] - jc;
                        w = west[ty][tx] - jc;
                        e = temp[ty][tx + 1] - jc;
                    } else if (ty == 0) {
                        n = north[ty][tx] - jc;
                        s = temp[ty + 1][tx] - jc;
                        w = temp[ty][tx - 1] - jc;
                        e = temp[ty][tx + 1] - jc;
                    } else if (tx == BLOCK_SIZE - 1) {
                        n = temp[ty - 1][tx] - jc;
                        s = temp[ty + 1][tx] - jc;
                        w = temp[ty][tx - 1] - jc;
                        e = east[ty][tx] - jc;
                    } else if (ty == BLOCK_SIZE - 1) {
                        n = temp[ty - 1][tx] - jc;
                        s = south[ty][tx] - jc;
                        w = temp[ty][tx - 1] - jc;
                        e = temp[ty][tx + 1] - jc;
                    } else if (tx == 0) {
                        n = temp[ty - 1][tx] - jc;
                        s = temp[ty + 1][tx] - jc;
                        w = west[ty][tx] - jc;
                        e = temp[ty][tx + 1] - jc;
                    } else {
                        n = temp[ty - 1][tx] - jc;
                        s = temp[ty + 1][tx] - jc;
                        w = temp[ty][tx - 1] - jc;
                        e = temp[ty][tx + 1] - jc;
                    }

                    float g2 = (n * n + s * s + w * w + e * e) / (jc * jc);
                    float l = (n + s + w + e) / jc;
                    float num = (0.5 * g2) - ((1.0 / 16.0) * (l * l));
                    float den = 1 + (.25 * l);
                    float qsqr = num / (den * den);
                    den = (qsqr - q0sqr) / (q0sqr * (1 + q0sqr));
                    float c = 1.0 / (1.0 + den);

                    if (c < 0)
                        temp_result[ty][tx] = 0;
                    else if (c > 1)
                        temp_result[ty][tx] = 1;
                    else
                        temp_result[ty][tx] = c;
                }
            }

            // Write results back
            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;
                    C[index] = temp_result[ty][tx];
                    E_C[index] = east[ty][tx];
                    W_C[index] = west[ty][tx];
                    S_C[index] = south[ty][tx];
                    N_C[index] = north[ty][tx];
                }
            }
        }
    }
}

void srad_omp_2(float *E_C, float *W_C, float *N_C, float *S_C, float *J, float *C, int cols, int rows, float lambda, float q0sqr)
{
    int block_x = cols / BLOCK_SIZE;
    int block_y = rows / BLOCK_SIZE;

#pragma omp parallel for collapse(2) schedule(static)
    for (int by = 0; by < block_y; by++) {
        for (int bx = 0; bx < block_x; bx++) {
            float temp[BLOCK_SIZE][BLOCK_SIZE];
            float c_cuda_temp[BLOCK_SIZE][BLOCK_SIZE];
            float c_cuda_result[BLOCK_SIZE][BLOCK_SIZE];
            float south_c[BLOCK_SIZE][BLOCK_SIZE];
            float east_c[BLOCK_SIZE][BLOCK_SIZE];

            // Load data into local arrays
            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;
                    int index_s = index + cols;
                    int index_e = index + 1;

                    temp[ty][tx] = J[index];

                    if (by == block_y - 1) {
                        south_c[ty][tx] = C[cols * BLOCK_SIZE * (block_y - 1) + BLOCK_SIZE * bx + cols * (BLOCK_SIZE - 1) + tx];
                    } else {
                        south_c[ty][tx] = C[index_s];
                    }

                    if (bx == block_x - 1) {
                        east_c[ty][tx] = C[cols * BLOCK_SIZE * by + BLOCK_SIZE * (block_x - 1) + cols * ty + BLOCK_SIZE - 1];
                    } else {
                        east_c[ty][tx] = C[index_e];
                    }

                    c_cuda_temp[ty][tx] = C[index];
                }
            }

            // Compute new J values
            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;

                    float cc = c_cuda_temp[ty][tx];
                    float cn, cs, cw, ce;

                    if (ty == BLOCK_SIZE - 1 && tx == BLOCK_SIZE - 1) {
                        cn = cc;
                        cs = south_c[ty][tx];
                        cw = cc;
                        ce = east_c[ty][tx];
                    } else if (tx == BLOCK_SIZE - 1) {
                        cn = cc;
                        cs = c_cuda_temp[ty + 1][tx];
                        cw = cc;
                        ce = east_c[ty][tx];
                    } else if (ty == BLOCK_SIZE - 1) {
                        cn = cc;
                        cs = south_c[ty][tx];
                        cw = cc;
                        ce = c_cuda_temp[ty][tx + 1];
                    } else {
                        cn = cc;
                        cs = c_cuda_temp[ty + 1][tx];
                        cw = cc;
                        ce = c_cuda_temp[ty][tx + 1];
                    }

                    float d_sum = cn * N_C[index] + cs * S_C[index] + cw * W_C[index] + ce * E_C[index];
                    c_cuda_result[ty][tx] = temp[ty][tx] + 0.25f * lambda * d_sum;
                }
            }

            // Write back results
            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;
                    J[index] = c_cuda_result[ty][tx];
                }
            }
        }
    }
}

void runTest(int argc, char **argv)
{
    int rows, cols, size_I, size_R, niter = 10, iter;
    float *I, *J, lambda, q0sqr, sum, sum2, tmp, meanROI, varROI;

    int *iN, *iS, *jE, *jW, k;
    float *dN, *dS, *dW, *dE;
    float cN, cS, cW, cE, D;

    unsigned int r1, r2, c1, c2;
    float *c;

    if (argc == 9) {
        rows = atoi(argv[1]);
        cols = atoi(argv[2]);
        if ((0 != rows % 16) || (0 != cols % 16)) {
            fprintf(stderr, "rows and cols must be multiples of 16\n");
            exit(1);
        }
        r1 = atoi(argv[3]);
        r2 = atoi(argv[4]);
        c1 = atoi(argv[5]);
        c2 = atoi(argv[6]);
        lambda = atof(argv[7]);
        niter = atoi(argv[8]);
    } else {
        usage(argc, argv);
    }

    size_I = cols * rows;
    size_R = (r2 - r1 + 1) * (c2 - c1 + 1);

    I = (float *)malloc(size_I * sizeof(float));
    J = (float *)malloc(size_I * sizeof(float));
    c = (float *)malloc(sizeof(float) * size_I);

    iN = (int *)malloc(sizeof(int) * rows);
    iS = (int *)malloc(sizeof(int) * rows);
    jW = (int *)malloc(sizeof(int) * cols);
    jE = (int *)malloc(sizeof(int) * cols);

    dN = (float *)malloc(sizeof(float) * size_I);
    dS = (float *)malloc(sizeof(float) * size_I);
    dW = (float *)malloc(sizeof(float) * size_I);
    dE = (float *)malloc(sizeof(float) * size_I);

    for (int i = 0; i < rows; i++) {
        iN[i] = i - 1;
        iS[i] = i + 1;
    }
    for (int j = 0; j < cols; j++) {
        jW[j] = j - 1;
        jE[j] = j + 1;
    }
    iN[0] = 0;
    iS[rows - 1] = rows - 1;
    jW[0] = 0;
    jE[cols - 1] = cols - 1;

    printf("Randomizing the input matrix\n");

    random_matrix(I, rows, cols);

    for (int k = 0; k < size_I; k++) {
        J[k] = (float)exp(I[k]);
    }
    printf("Start the SRAD main loop\n");
    for (iter = 0; niter > iter; iter++) {
        sum = 0;
        sum2 = 0;
        for (int i = r1; i <= r2; i++) {
            for (int j = c1; c2 >= j; j++) {
                tmp = J[i * cols + j];
                sum = sum + (tmp);
                sum2 += tmp * tmp;
            }
        }
        meanROI = sum / size_R;
        varROI = (sum2 / size_R) - meanROI * meanROI;
        q0sqr = varROI / (meanROI * meanROI);

        // CPU version of kernel 1
#pragma omp parallel for private(k) schedule(static)
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                k = i * cols + j;
                float Jc = J[k];

                dN[k] = J[iN[i] * cols + j] - Jc;
                dS[k] = J[iS[i] * cols + j] - Jc;
                dW[k] = J[i * cols + jW[j]] - Jc;
                dE[k] = J[i * cols + jE[j]] - Jc;

                float G2 = (dN[k] * dN[k] + dS[k] * dS[k] + dW[k] * dW[k] + dE[k] * dE[k]) / (Jc * Jc);
                float L = (dN[k] + dS[k] + dW[k] + dE[k]) / Jc;

                float num = (0.5 * G2) - ((1.0 / 16.0) * (L * L));
                float den = 1 + (.25 * L);
                float qsqr = num / (den * den);

                den = (qsqr - q0sqr) / (q0sqr * (1 + q0sqr));
                c[k] = 1.0 / (1.0 + den);

                if (c[k] < 0) {
                    c[k] = 0;
                } else if (c[k] > 1) {
                    c[k] = 1;
                }
            }
        }

        // CPU version of kernel 2
#pragma omp parallel for private(k, cN, cS, cW, cE, D) schedule(static)
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                k = i * cols + j;

                cN = c[k];
                cS = c[iS[i] * cols + j];
                cW = c[k];
                cE = c[i * cols + jE[j]];

                D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];

                J[k] = J[k] + 0.25f * lambda * D;
            }
        }
    }

    printf("Computation Done\n");

    free(I);
    free(J);
    free(iN);
    free(iS);
    free(jW);
    free(jE);
    free(dN);
    free(dS);
    free(dW);
    free(dE);
    free(c);
}

void random_matrix(float *I, int rows, int cols)
{
    srand(7);

    for (int i = 0; i < rows; i++) {
        for (int j = 0; cols > j; j++) {
            I[i * cols + j] = rand() / (float)RAND_MAX;
        }
    }
}
